  handoff_needed = true;
  reply_mode = 'handoff_admin';
  should_call_resolver = false;
  next_action = 'escalate_to_human';
}

const rules_output = {
  should_call_resolver,
  reply_mode,
  handoff_needed,
  next_action,
  confidence
};

return [{
  json: {
    ...input,
    rules_output
  }
}];

