    }, (res) => {
      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });
      res.on('end', () => {
        if ((res.statusCode ?? 500) >= 400) {
          return reject(new Error('OpenRouter HTTP ' + String(res.statusCode ?? 500) + ': ' + data));
        }
        resolve(data);
      });
    });

    req.on('error', reject);
    req.write(requestPayload);
    req.end();
  });

  let parsedResponse = null;
  try {
    parsedResponse = JSON.parse(responseBody);
  } catch {}

  reply_text = parseReplyPayload(parsedResponse?.choices?.[0]?.message?.content)
    || parseReplyPayload(parsedResponse?.output_text)
    || parseReplyPayload(parsedResponse?.text)
    || parseReplyPayload(parsedResponse)
    || '';
} catch (error) {
  reply_text = '';
}

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    understanding_meta,
    rules_output,
    resolver_output,
